    43→            "F" | "f" | "FLY" | "fly" | "Fly" => Ok(ChalkMarker::Fly),
    44→            "d" | "D" | "DISCUSSION" | "discussion" | "Discussion" => Ok(ChalkMarker::Discussion),
    45→            _ => Err(format!(
    46→                "Invalid marker type '{}'. Valid: A(pproach), W(rap), F(ly), d(iscussion)",
    47→                s
    48→            )),
    49→        }
    50→    }
